
'use client';

import * as React from 'react';
import { mockProjects } from '@/lib/mock-data';
import { ProjectCard } from '@/components/project-card';
import { Input } from '@/components/ui/input';
import { Search } from 'lucide-react';

export default function ProjectsPage() {
  const [searchTerm, setSearchTerm] = React.useState('');
  
  const approvedProjects = mockProjects.filter(
    (p) => p.status === 'En lista de espera'
  );

  const filteredProjects = approvedProjects.filter(project =>
    project.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    project.abstract.toLowerCase().includes(searchTerm.toLowerCase()) ||
    project.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline">Explorar Proyectos</h1>
        <p className="text-muted-foreground">
          Encuentra proyectos aprobados que están buscando miembros y únete a un equipo.
        </p>
      </div>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
        <Input
          type="search"
          placeholder="Buscar por título, categoría o palabra clave..."
          className="pl-10 w-full md:w-1/2 lg:w-1/3"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {filteredProjects.length > 0 ? (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {filteredProjects.map((project) => (
            <ProjectCard key={project.id} project={project} />
          ))}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center text-center p-8 border-2 border-dashed rounded-lg h-64">
          <p className="text-muted-foreground">
            No se encontraron proyectos que coincidan con tu búsqueda.
          </p>
        </div>
      )}
    </div>
  );
}
